from fastapi import FastAPI, Depends, HTTPException
from sqlmodel import Session, select

app = FastAPI()

def get_session():
    with Session(engine) as session:
        yield session

@app.post("/heroes", response_model=HeroRead)
def create_hero(hero: HeroCreate, db: Session = Depends(get_session)):
    db_hero = Hero.model_validate(hero)
    db.add(db_hero)
    db.commit()
    db.refresh(db_hero)
    return db_hero

@app.get("/heroes", response_model=list[HeroRead])
def read_heroes(db: Session = Depends(get_session)):
    return db.exec(select(Hero)).all()

@app.get("/heroes/{hero_id}", response_model=HeroRead)
def read_hero(hero_id: int, db: Session = Depends(get_session)):
    hero = db.get(Hero, hero_id)
    if not hero:
        raise HTTPException(status_code=404, detail="Hero not found")
    return hero

@app.delete("/heroes/{hero_id}")
def delete_hero(hero_id: int, db: Session = Depends(get_session)):
    hero = db.get(Hero, hero_id)
    if not hero:
        raise HTTPException(status_code=404, detail="Hero not found")
    db.delete(hero)
    db.commit()
    return {"deleted": True}

from jose import JWTError, jwt
from datetime import datetime, timedelta, timezone
from fastapi import HTTPException, status

SECRET_KEY = "your-secret-key-from-env"
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 30

def create_access_token(data: dict) -> str:
    to_encode = data.copy()
    expire = datetime.now(timezone.utc) + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode["exp"] = expire
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)

def decode_token(token: str) -> dict:
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        username = payload.get("sub")
        if username is None:
            raise HTTPException(status_code=401, detail="Invalid token")
        return {"username": username}
    except JWTError:
        raise HTTPException(status_code=401, detail="Could not validate token")

from passlib.context import CryptContext
from fastapi import FastAPI, Depends, HTTPException
from pydantic import BaseModel

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")

def hash_password(password: str) -> str:
    return pwd_context.hash(password)

def verify_password(plain: str, hashed: str) -> bool:
    return pwd_context.verify(plain, hashed)

class UserIn(BaseModel):
    username: str
    password: str

app = FastAPI()

@app.post("/register")
def register(user: UserIn):
    hashed = hash_password(user.password)
    # store username + hashed in database
    return {"username": user.username, "hashed": hashed}

from fastapi import FastAPI, BackgroundTasks

app = FastAPI()

def write_log(message: str):
    with open("log.txt", "a") as f:
        f.write(message + "\n")

def send_welcome_email(email: str):
    print(f"Sending welcome email to {email}")

@app.post("/users")
async def create_user(email: str, background_tasks: BackgroundTasks):
    background_tasks.add_task(write_log, f"User created: {email}")
    background_tasks.add_task(send_welcome_email, email)
    return {"email": email, "status": "created"}
